const body = ($json.body && typeof $json.body === 'object') ? $json.body : $json;
const template = body.template && typeof body.template === 'object' ? body.template : {};
const slots = Array.isArray(template.slots) ? template.slots : [];
const previousVariants = Array.isArray(body.previousVariants) ? body.previousVariants : [];

const templateId = String(template.id ?? '').trim();
const itemId = String(template.itemId ?? template.item_id ?? '').trim();
const sourceLanguage = String(template.sourceLanguage ?? template.source_language ?? '').trim() || 'original';
const rawText = String(template.rawText ?? template.raw_text ?? '').trim();
const markedText = String(template.markedText ?? template.marked_text ?? '').trim();
const themeKeyword = String(body.themeKeyword ?? body.theme_keyword ?? '').trim();
const llmModel = String(body.model ?? 'gpt-5.4-mini').trim() || 'gpt-5.4-mini';

if (!templateId) throw new Error('Missing template.id');
if (!itemId) throw new Error('Missing template.itemId');
if (!markedText) throw new Error('Missing template.markedText');
if (!themeKeyword) throw new Error('Missing themeKeyword');
if (!Array.isArray(slots) || slots.length === 0) throw new Error('Template slots are required');

const normalizedSlots = slots.map((slot) => ({
  id: String(slot.id ?? '').trim(),
  group: String(slot.group ?? 'content').trim() || 'content',
  label: String(slot.label ?? slot.id ?? '').trim() || String(slot.id ?? '').trim(),
  original_text: String(slot.original_text ?? slot.originalText ?? '').trim(),
  role: String(slot.role ?? '').trim(),
  instruction: String(slot.instruction ?? '').trim(),
}));

for (const slot of normalizedSlots) {
  if (!slot.id) throw new Error('Every slot must include an id');
  if (!slot.original_text) throw new Error(`Slot ${slot.id} is missing original_text`);
}

const systemPrompt = [
  'You are a prompt remix engine for an image prompt library.',
  'You receive a marked prompt template with immutable skeleton text and editable slot regions.',
  'You must preserve the skeleton exactly and only propose new text for the provided slots.',
  'Do not return a full prompt. Return slot values only.',
  'When the user changes the theme keyword, rewrite the variable regions holistically so the whole prompt stays stylistically coherent.',
  'Different slots may need coordinated changes. Think across all slots together before responding.',
  'Never invent or remove slot ids.',
  'Return valid JSON only with keys slotValues and changeSummary.',
  'slotValues must be an array of objects with keys slot_id and text.',
  'You must include every slot exactly once.',
  'text must contain only the replacement content for that slot, without any slot markers or extra commentary.',
  'changeSummary should briefly explain the coordinated rewrite.'
].join(' ');

const slotListText = JSON.stringify(normalizedSlots, null, 2);
const previousVariantText = JSON.stringify(previousVariants.map((variant) => ({
  iteration: variant.iteration,
  renderedText: variant.renderedText ?? variant.rendered_text ?? '',
  slotValues: variant.slotValues ?? variant.slot_values ?? [],
  changeSummary: variant.changeSummary ?? variant.change_summary ?? '',
})), null, 2);

const userPrompt = [
  'Rewrite the marked prompt slots for a new theme.',
  `Template ID: ${templateId}`,
  `Item ID: ${itemId}`,
  `Source language: ${sourceLanguage}`,
  `Theme keyword: ${themeKeyword}`,
  '',
  'Marked template:',
  markedText,
  '',
  'Original prompt:',
  rawText || '(not provided)',
  '',
  'Slots:',
  slotListText,
  '',
  'Rejected / previous variants to avoid repeating too closely:',
  previousVariantText,
  '',
  'Return JSON only.',
].join('\n');

return [{
  json: {
    slotIds: normalizedSlots.map((slot) => slot.id),
    requestPayload: {
      model: llmModel,
      stream: true,
      input: [
        {
          role: 'system',
          content: [{ type: 'input_text', text: systemPrompt }],
        },
        {
          role: 'user',
          content: [{ type: 'input_text', text: userPrompt }],
        },
      ],
      text: {
        format: {
          type: 'json_object',
        },
      },
      max_output_tokens: 1600,
    },
  },
}];

const source = $json;

const raw = typeof source.body === 'string'
  ? source.body
  : typeof source.data === 'string'
    ? source.data
    : typeof source === 'string'
      ? source
      : JSON.stringify(source);

if (typeof source.statusCode === 'number' && source.statusCode >= 400) {
  throw new Error(raw.slice(0, 2000));
}

const safeParseLoose = (value) => {
  if (typeof value !== 'string') return value;
  const trimmed = value.trim();
  if (!trimmed) return value;
  const normalized = trimmed
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
  if (!(normalized.startsWith('{') || normalized.startsWith('['))) return value;
  try {
    return JSON.parse(normalized);
  } catch {
    return value;
  }
};

const textCandidates = [];
const objectCandidates = [];
const seenText = new Set();
let deltaBuffer = '';

const pushText = (value) => {
  if (typeof value !== 'string') return;
  const text = value.trim();
  if (!text || seenText.has(text)) return;
  seenText.add(text);
  textCandidates.push(text);
};

const pushObject = (value) => {
  if (!value || typeof value !== 'object') return;
  objectCandidates.push(value);
};

const walk = (node) => {
  if (!node) return;
  if (typeof node === 'string') {
    const parsed = safeParseLoose(node);
    if (parsed !== node) {
      walk(parsed);
      return;
    }
    pushText(node);
    return;
  }
  if (Array.isArray(node)) {
    node.forEach(walk);
    return;
  }
  if (typeof node !== 'object') return;

  pushObject(node);

  const nodeType = typeof node.type === 'string' ? node.type : '';
  const nodeEvent = typeof node.event === 'string' ? node.event : '';
  if (typeof node.delta === 'string' && /output_text\.delta$/i.test(nodeType || nodeEvent || '')) {
    deltaBuffer += node.delta;
  }
  if (typeof node.text === 'string' && /output_text\.done$/i.test(nodeType || nodeEvent || '')) {
    pushText(node.text);
  }
  if (node.part && typeof node.part === 'object' && typeof node.part.text === 'string') {
    pushText(node.part.text);
  }
  if (typeof node.output_text === 'string') {
    pushText(node.output_text);
  }
  if (Array.isArray(node.output_text)) {
    for (const chunk of node.output_text) {
      if (typeof chunk === 'string') pushText(chunk);
      else if (chunk && typeof chunk === 'object' && typeof chunk.text === 'string') pushText(chunk.text);
    }
  }

  for (const [key, value] of Object.entries(node)) {
    if (key === 'delta' || key === 'text' || key === 'output_text') continue;
    walk(value);
  }
};

const normalized = raw.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
const blocks = normalized.split('\n\n').map((item) => item.trim()).filter(Boolean);
let parsedSse = false;
for (const block of blocks) {
  const lines = block.split('\n');
  const dataLines = [];
  let eventType = '';
  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith(':')) continue;
    if (trimmed.startsWith('event:')) {
      eventType = trimmed.slice(6).trim();
      continue;
    }
    if (trimmed.startsWith('data:')) dataLines.push(trimmed.slice(5).trim());
  }
  if (dataLines.length === 0) continue;
  parsedSse = true;
  const merged = dataLines.join('\n').trim();
  if (!merged || merged === '[DONE]') continue;
  try {
    const payload = JSON.parse(merged);
    if (eventType && (!payload.type || typeof payload.type !== 'string')) payload.type = eventType;
    walk(payload);
  } catch {
    pushText(merged);
  }
}

if (!parsedSse) walk(safeParseLoose(normalized));
if (deltaBuffer.trim()) pushText(deltaBuffer);

const parsedTextObjects = textCandidates.map((item) => safeParseLoose(item)).filter((item) => item && typeof item === 'object');
const allObjects = [source, ...objectCandidates, ...parsedTextObjects].filter((item) => item && typeof item === 'object');

const readByPath = (payload, path) => {
  let cursor = payload;
  for (const segment of path) {
    if (!cursor || typeof cursor !== 'object') return undefined;
    cursor = cursor[segment];
  }
  return cursor;
};

let slotValues = null;
let changeSummary = '';
for (const candidate of allObjects) {
  const nextSlotValues = readByPath(candidate, ['slotValues']) ?? readByPath(candidate, ['slot_values']) ?? readByPath(candidate, ['data', 'slotValues']) ?? readByPath(candidate, ['result', 'slotValues']);
  if (!slotValues && Array.isArray(nextSlotValues)) slotValues = nextSlotValues;
  if (!changeSummary) {
    const nextSummary = readByPath(candidate, ['changeSummary']) ?? readByPath(candidate, ['change_summary']) ?? readByPath(candidate, ['notes']) ?? readByPath(candidate, ['data', 'changeSummary']);
    if (typeof nextSummary === 'string' && nextSummary.trim()) changeSummary = nextSummary.trim();
  }
}

if (!slotValues) {
  throw new Error('Workflow returned no slotValues array.');
}

const normalizedSlotValues = slotValues.map((value) => {
  const slotId = String(value.slot_id ?? value.slotId ?? '').trim();
  const text = String(value.text ?? '').trim();
  if (!slotId) throw new Error('Each slot value must include slot_id.');
  if (!text) throw new Error(`Slot ${slotId} is missing replacement text.`);
  return { slot_id: slotId, text };
});

const expectedSlotIds = $item(0).$node['Prepare Prompt Template Generate Payload'].json.slotIds;
const seenIds = new Set();
for (const value of normalizedSlotValues) {
  if (seenIds.has(value.slot_id)) throw new Error(`Duplicate slot_id: ${value.slot_id}`);
  seenIds.add(value.slot_id);
}
for (const expectedId of expectedSlotIds) {
  if (!seenIds.has(expectedId)) throw new Error(`Missing slot value for ${expectedId}`);
}
if (normalizedSlotValues.length !== expectedSlotIds.length) {
  throw new Error('Workflow returned an unexpected number of slot values.');
}

return [{
  json: {
    slotValues: normalizedSlotValues,
    changeSummary,
  },
}];
